SELECT COUNT(bh.history_id) AS total_severity_changes
FROM bug_history bh
WHERE bh.field_name = 'severity' AND bh.from_value <> bh.to_value;

SELECT COUNT(*) 
FROM file_attachments 
WHERE uploaded_by = 1;

SELECT to_value
FROM bug_history
WHERE change_date >= '2023-05-01';

SELECT SUM(p.actual_cost) AS total_actual_cost
FROM projects p
WHERE p.project_id IN (
    SELECT b.project_id
    FROM bugs b
    WHERE b.severity = 'high'
) AND p.actual_cost > (
    SELECT AVG(budget) 
    FROM projects
);
